from itertools import*
def p(g):
 W=len(g[0]);o=[]
 for k,G in groupby(g,any):
  L=[*G]
  if k:
   t=len(L);r=L[0];v=max(r);m=r.count(v);a=r.index(v)
   o+=[[v*(p<=c<=q if x%~-t<1 else c in(p,q))for c in range(W)]for x in range(t)for p,q in[(a+min(max(x,1),t-2),a+m+min(x,t-3))]]
  else:o+=L
 return o

